MLflow Parity Helpers

nbdev source for local MLflow parity stack helpers (PostgreSQL + S3-compatible artifacts).


from __future__ import annotations

from dataclasses import dataclass
import json
import os
from pathlib import Path
from typing import Any, Mapping


@dataclass(frozen=True)
class LocalMlflowParityConfig:
    """Configuration for local MLflow parity stack."""

    postgres_user: str = "mlflow"
    postgres_password: str = "mlflow"
    postgres_db: str = "mlflow"
    postgres_port: int = 5432
    minio_access_key: str = "minioadmin"
    minio_secret_key: str = "minioadmin"
    minio_bucket: str = "mlflow"
    minio_api_port: int = 9000
    minio_console_port: int = 9001
    mlflow_port: int = 5000
    mlflow_host: str = "0.0.0.0"
    compose_project_name: str = "mlflow-parity"

    @property
    def backend_store_uri(self) -&gt; str:
        return (
            f"postgresql://{self.postgres_user}:{self.postgres_password}"
            f"@localhost:{self.postgres_port}/{self.postgres_db}"
        )

    @property
    def artifacts_destination(self) -&gt; str:
        return f"s3://{self.minio_bucket}"

    @property
    def mlflow_tracking_uri(self) -&gt; str:
        return f"http://localhost:{self.mlflow_port}"

    @property
    def minio_endpoint(self) -&gt; str:
        return f"http://localhost:{self.minio_api_port}"


@dataclass(frozen=True)
class MlflowStorageConfig:
    """Runtime MLflow storage configuration aligned to PostgreSQL + S3."""

    backend_store_uri: str
    artifacts_destination: str
    tracking_uri: str
    aws_access_key_id: str
    aws_secret_access_key: str
    s3_endpoint_url: str | None = None


def render_local_compose_config(config: LocalMlflowParityConfig) -&gt; dict[str, Any]:
    """Render a Docker Compose config for local PostgreSQL + MinIO + MLflow."""
    postgres_image = "postgres:16-alpine"
    minio_image = "minio/minio:latest"
    mlflow_image = "ghcr.io/mlflow/mlflow:v2.14.2"
    return {
        "name": config.compose_project_name,
        "services": {
            "postgres": {
                "image": postgres_image,
                "environment": {
                    "POSTGRES_USER": config.postgres_user,
                    "POSTGRES_PASSWORD": config.postgres_password,
                    "POSTGRES_DB": config.postgres_db,
                },
                "ports": [f"{config.postgres_port}:5432"],
                "healthcheck": {
                    "test": ["CMD-SHELL", "pg_isready -U $${POSTGRES_USER}"],
                    "interval": "5s",
                    "timeout": "3s",
                    "retries": 20,
                },
            },
            "minio": {
                "image": minio_image,
                "command": "server /data --console-address :9001",
                "environment": {
                    "MINIO_ROOT_USER": config.minio_access_key,
                    "MINIO_ROOT_PASSWORD": config.minio_secret_key,
                },
                "ports": [
                    f"{config.minio_api_port}:9000",
                    f"{config.minio_console_port}:9001",
                ],
            },
            "mlflow": {
                "image": mlflow_image,
                "depends_on": {"postgres": {"condition": "service_healthy"}, "minio": {}},
                "command": [
                    "mlflow",
                    "server",
                    "--host",
                    config.mlflow_host,
                    "--port",
                    str(config.mlflow_port),
                    "--backend-store-uri",
                    (
                        f"postgresql://{config.postgres_user}:{config.postgres_password}"
                        f"@postgres:5432/{config.postgres_db}"
                    ),
                    "--artifacts-destination",
                    f"s3://{config.minio_bucket}",
                ],
                "environment": {
                    "AWS_ACCESS_KEY_ID": config.minio_access_key,
                    "AWS_SECRET_ACCESS_KEY": config.minio_secret_key,
                    "MLFLOW_S3_ENDPOINT_URL": "http://minio:9000",
                },
                "ports": [f"{config.mlflow_port}:{config.mlflow_port}"],
            },
        },
    }


def write_local_compose_file(path: Path, config: LocalMlflowParityConfig) -&gt; Path:
    """Write compose configuration as JSON-compatible YAML subset."""
    path.parent.mkdir(parents=True, exist_ok=True)
    compose_dict = render_local_compose_config(config)
    path.write_text(json.dumps(compose_dict, indent=2) + "\n", encoding="utf-8")
    return path


def build_mlflow_server_command(config: LocalMlflowParityConfig) -&gt; list[str]:
    """Build an MLflow server command matching the parity posture."""
    return [
        "mlflow",
        "server",
        "--host",
        config.mlflow_host,
        "--port",
        str(config.mlflow_port),
        "--backend-store-uri",
        config.backend_store_uri,
        "--artifacts-destination",
        config.artifacts_destination,
    ]


def build_mlflow_runtime_env(config: LocalMlflowParityConfig) -&gt; dict[str, str]:
    """Build environment variables for S3-compatible MLflow artifact storage."""
    return {
        "MLFLOW_TRACKING_URI": config.mlflow_tracking_uri,
        "AWS_ACCESS_KEY_ID": config.minio_access_key,
        "AWS_SECRET_ACCESS_KEY": config.minio_secret_key,
        "MLFLOW_S3_ENDPOINT_URL": config.minio_endpoint,
    }


def resolve_mlflow_storage_config(
    env: Mapping[str, str] | None = None,
) -&gt; MlflowStorageConfig:
    """Resolve MLflow runtime settings with PostgreSQL + S3 parity defaults."""
    values = env or os.environ
    return MlflowStorageConfig(
        backend_store_uri=values.get(
            "MLFLOW_BACKEND_STORE_URI",
            "postgresql://mlflow:mlflow@localhost:5432/mlflow",
        ),
        artifacts_destination=values.get("MLFLOW_ARTIFACTS_DESTINATION", "s3://mlflow"),
        tracking_uri=values.get("MLFLOW_TRACKING_URI", "http://localhost:5000"),
        aws_access_key_id=values.get("AWS_ACCESS_KEY_ID", "minioadmin"),
        aws_secret_access_key=values.get("AWS_SECRET_ACCESS_KEY", "minioadmin"),
        s3_endpoint_url=values.get("MLFLOW_S3_ENDPOINT_URL"),
    )


def build_mlflow_runtime_env_from_storage(config: MlflowStorageConfig) -&gt; dict[str, str]:
    """Build process env vars from resolved PostgreSQL + S3 MLflow settings."""
    env = {
        "MLFLOW_TRACKING_URI": config.tracking_uri,
        "MLFLOW_BACKEND_STORE_URI": config.backend_store_uri,
        "MLFLOW_ARTIFACTS_DESTINATION": config.artifacts_destination,
        "AWS_ACCESS_KEY_ID": config.aws_access_key_id,
        "AWS_SECRET_ACCESS_KEY": config.aws_secret_access_key,
    }
    if config.s3_endpoint_url:
        env["MLFLOW_S3_ENDPOINT_URL"] = config.s3_endpoint_url
    return env

Web UI Backend Contracts

nbdev source for immutable notebook execution requests and MLflow-first run visibility helpers.


from __future__ import annotations

from dataclasses import asdict, dataclass, field
from datetime import datetime, timezone
from typing import Any, Literal


ExecutionTarget = Literal["local-replica", "lambda-slurm", "aws-kubernetes"]
RevisionKind = Literal["commit", "tag", "approved-ref"]
RunStatus = Literal["queued", "running", "finished", "failed", "canceled", "unknown"]


def _utc_now() -&gt; str:
    return datetime.now(timezone.utc).isoformat()


def _normalize_base_url(base_url: str) -&gt; str:
    return base_url.strip().rstrip("/")


def build_mlflow_run_url(mlflow_base_url: str, run_id: str) -&gt; str:
    """Build a stable deep link to the MLflow run detail page."""
    normalized = _normalize_base_url(mlflow_base_url)
    if not normalized:
        raise ValueError("mlflow_base_url must be non-empty")
    if not run_id.strip():
        raise ValueError("run_id must be non-empty")
    return f"{normalized}/#/experiments/0/runs/{run_id.strip()}"


def _normalize_status(raw_status: Any) -&gt; RunStatus:
    status = str(raw_status).strip().lower()
    if status == "queued":
        return "queued"
    if status == "running":
        return "running"
    if status == "finished":
        return "finished"
    if status == "failed":
        return "failed"
    if status == "canceled":
        return "canceled"
    return "unknown"


@dataclass(frozen=True)
class NotebookRevision:
    """Immutable notebook reference used as execution source-of-truth."""

    repository: str
    notebook_path: str
    revision: str
    revision_kind: RevisionKind = "commit"

    def as_dict(self) -&gt; dict[str, Any]:
        return asdict(self)

    def validate(self) -&gt; None:
        if not self.repository.strip():
            raise ValueError("repository must be non-empty")
        if not self.notebook_path.strip():
            raise ValueError("notebook_path must be non-empty")
        if not self.revision.strip():
            raise ValueError("revision must be non-empty")
        if self.revision_kind == "commit":
            cleaned = self.revision.strip().lower()
            if len(cleaned) &lt; 7 or any(c not in "0123456789abcdef" for c in cleaned):
                raise ValueError("commit revisions must be a git SHA (&gt;=7 hex chars)")


@dataclass(frozen=True)
class NotebookExecutionRequest:
    """Web UI request payload for environment-specific execution."""

    notebook: NotebookRevision
    target: ExecutionTarget
    requested_by: str
    config_profile: str = "default"
    parameters: dict[str, Any] = field(default_factory=dict)
    request_id: str = ""
    requested_at: str = ""

    def with_defaults(self, *, request_id: str) -&gt; "NotebookExecutionRequest":
        if not request_id.strip():
            raise ValueError("request_id must be non-empty")
        return NotebookExecutionRequest(
            notebook=self.notebook,
            target=self.target,
            requested_by=self.requested_by,
            config_profile=self.config_profile,
            parameters=self.parameters,
            request_id=request_id,
            requested_at=self.requested_at or _utc_now(),
        )

    def validate(self) -&gt; None:
        self.notebook.validate()
        if not self.requested_by.strip():
            raise ValueError("requested_by must be non-empty")
        if not self.config_profile.strip():
            raise ValueError("config_profile must be non-empty")
        if self.request_id and not self.request_id.strip():
            raise ValueError("request_id must be non-empty when provided")

    def as_job_spec(self) -&gt; dict[str, Any]:
        self.validate()
        if not self.request_id:
            raise ValueError("request_id must be set before producing a job spec")
        if not self.requested_at:
            raise ValueError("requested_at must be set before producing a job spec")
        return {
            "request_id": self.request_id,
            "requested_at": self.requested_at,
            "requested_by": self.requested_by,
            "target": self.target,
            "config_profile": self.config_profile,
            "notebook": self.notebook.as_dict(),
            "parameters": self.parameters,
        }


@dataclass(frozen=True)
class RunVisibility:
    """Web UI summary model with MLflow-first observability linkage."""

    run_id: str
    status: RunStatus
    started_at: str
    finished_at: str | None
    model_version: str | None
    mlflow_run_url: str

    def as_dict(self) -&gt; dict[str, Any]:
        return asdict(self)


def summarize_run_for_webui(
    run_metadata: dict[str, Any], *, mlflow_base_url: str
) -&gt; RunVisibility:
    """Map backend run metadata to an MLflow-linked Web UI summary."""
    run_id = str(run_metadata.get("run_id", "")).strip()
    if not run_id:
        raise ValueError("run_metadata.run_id is required")

    normalized_status = _normalize_status(run_metadata.get("status", "unknown"))
    started_at = str(run_metadata.get("started_at", "")).strip() or _utc_now()
    finished_at_raw = run_metadata.get("finished_at")
    finished_at = str(finished_at_raw).strip() if finished_at_raw is not None else None
    model_version_raw = run_metadata.get("model_version")
    model_version = (
        str(model_version_raw).strip() if model_version_raw is not None else None
    )

    return RunVisibility(
        run_id=run_id,
        status=normalized_status,
        started_at=started_at,
        finished_at=finished_at or None,
        model_version=model_version or None,
        mlflow_run_url=build_mlflow_run_url(mlflow_base_url, run_id),
    )

Execution Backends

nbdev source for local execution adapter and Slurm/Kubernetes mapping helpers.


from __future__ import annotations

from dataclasses import dataclass
from datetime import datetime, timezone
from pathlib import Path
from typing import Any, Callable
from uuid import uuid4

from ml_deploy.mlflow_parity import resolve_mlflow_storage_config
from ml_deploy.vertical_slice import execute_first_vertical_slice
from ml_deploy.webui_contracts import NotebookExecutionRequest, RunVisibility, summarize_run_for_webui


def _utc_now() -&gt; str:
    return datetime.now(timezone.utc).isoformat()


@dataclass(frozen=True)
class LocalExecutionResult:
    request_id: str
    run_visibility: RunVisibility
    output_dir: Path
    prediction_log_path: Path


class LocalExecutionAdapter:
    """Adapter that maps normalized web UI requests to local execution."""

    def __init__(self, mlflow_base_url: str, runner: Callable[..., dict[str, Any]] | None = None):
        self.mlflow_base_url = mlflow_base_url
        self._runner = runner or execute_first_vertical_slice

    def submit(
        self,
        request: NotebookExecutionRequest,
        *,
        work_dir: Path,
        tracking_uri: str,
        request_id: str | None = None,
    ) -&gt; LocalExecutionResult:
        resolved_request = request.with_defaults(request_id=request_id or f"req-{uuid4().hex[:12]}")
        job_spec = resolved_request.as_job_spec()

        run_payload = self._runner(work_dir, tracking_uri=tracking_uri)
        run_id = run_payload["training_outcome"].mlflow_run_id
        run_summary = summarize_run_for_webui(
            {
                "run_id": run_id,
                "status": "finished",
                "started_at": _utc_now(),
                "finished_at": _utc_now(),
                "model_version": run_payload["packaged"]["model_version_record"][
                    "model_version_identifier"
                ],
                "request_id": job_spec["request_id"],
            },
            mlflow_base_url=self.mlflow_base_url,
        )

        return LocalExecutionResult(
            request_id=job_spec["request_id"],
            run_visibility=run_summary,
            output_dir=run_payload["output_dir"],
            prediction_log_path=run_payload["prediction_log_path"],
        )


@dataclass(frozen=True)
class BackendSubmission:
    request_id: str
    backend: str
    status: str
    submission_payload: dict[str, Any]
    run_visibility: RunVisibility | None = None
    prediction_log_path: Path | None = None


class ExecutionOrchestrator:
    """Route normalized notebook requests to local, Slurm, or Kubernetes execution backends."""

    def __init__(self, mlflow_base_url: str, local_adapter: LocalExecutionAdapter | None = None):
        self._local_adapter = local_adapter or LocalExecutionAdapter(mlflow_base_url)

    @staticmethod
    def _resolve_backend(target: str) -&gt; str:
        normalized = target.strip().lower()
        if normalized in {"local", "local-replica"}:
            return "local"
        if normalized in {"lambda-slurm", "slurm"}:
            return "slurm"
        if normalized in {"aws-kubernetes", "kubernetes", "k8s"}:
            return "kubernetes"
        raise ValueError(f"Unsupported execution target: {target}")

    def submit(
        self,
        request: NotebookExecutionRequest,
        *,
        work_dir: Path,
        tracking_uri: str | None = None,
        request_id: str | None = None,
    ) -&gt; BackendSubmission:
        resolved_request = request.with_defaults(request_id=request_id or f"req-{uuid4().hex[:12]}")
        job_spec = resolved_request.as_job_spec()
        backend = self._resolve_backend(job_spec["target"])

        if backend == "local":
            runtime_tracking_uri = tracking_uri or resolve_mlflow_storage_config().tracking_uri
            local_result = self._local_adapter.submit(
                resolved_request,
                work_dir=work_dir,
                tracking_uri=runtime_tracking_uri,
                request_id=job_spec["request_id"],
            )
            return BackendSubmission(
                request_id=local_result.request_id,
                backend=backend,
                status="completed",
                submission_payload=job_spec,
                run_visibility=local_result.run_visibility,
                prediction_log_path=local_result.prediction_log_path,
            )

        if backend == "slurm":
            submission_payload = map_to_slurm_job_spec(job_spec)
        else:
            submission_payload = map_to_kubernetes_job_spec(job_spec)

        return BackendSubmission(
            request_id=job_spec["request_id"],
            backend=backend,
            status="submitted",
            submission_payload=submission_payload,
        )


def map_to_slurm_job_spec(job_spec: dict[str, Any]) -&gt; dict[str, Any]:
    """Map normalized job spec to a Slurm submission payload."""
    notebook = job_spec["notebook"]
    return {
        "scheduler": "slurm",
        "job_name": f"nb-{job_spec['request_id']}",
        "command": "python -m ml_deploy.jobs.run_notebook",
        "arguments": [
            f"--repository={notebook['repository']}",
            f"--notebook-path={notebook['notebook_path']}",
            f"--revision={notebook['revision']}",
            f"--target={job_spec['target']}",
            f"--config-profile={job_spec['config_profile']}",
        ],
        "environment": {
            "REQUEST_ID": job_spec["request_id"],
            "REQUESTED_BY": job_spec["requested_by"],
        },
    }


def map_to_kubernetes_job_spec(job_spec: dict[str, Any]) -&gt; dict[str, Any]:
    """Map normalized job spec to a Kubernetes Job manifest."""
    notebook = job_spec["notebook"]
    return {
        "apiVersion": "batch/v1",
        "kind": "Job",
        "metadata": {"name": f"nb-{job_spec['request_id']}"},
        "spec": {
            "template": {
                "spec": {
                    "restartPolicy": "Never",
                    "containers": [
                        {
                            "name": "notebook-runner",
                            "image": "python:3.13-slim",
                            "args": [
                                "python",
                                "-m",
                                "ml_deploy.jobs.run_notebook",
                                f"--repository={notebook['repository']}",
                                f"--notebook-path={notebook['notebook_path']}",
                                f"--revision={notebook['revision']}",
                                f"--target={job_spec['target']}",
                                f"--config-profile={job_spec['config_profile']}",
                            ],
                            "env": [
                                {"name": "REQUEST_ID", "value": job_spec["request_id"]},
                                {"name": "REQUESTED_BY", "value": job_spec["requested_by"]},
                            ],
                        }
                    ],
                }
            }
        },
    }
